<script>
// Reveal on scroll
const obs = new IntersectionObserver(e => e.forEach(x => {
  if (x.isIntersecting) x.target.classList.add('vis');
}), { threshold: .06 });
document.querySelectorAll('.slide').forEach(s => obs.observe(s));

// Gantt animation
const go = new IntersectionObserver(e => e.forEach(x => {
  if (x.isIntersecting) x.target.querySelectorAll('.gbar').forEach((b, i) => setTimeout(() => b.classList.add('loaded'), i * 65));
}), { threshold: .2 });
document.querySelectorAll('.gantt').forEach(g => go.observe(g));

// Top bar active
const navLinks = document.querySelectorAll('.tb-nav a');
const so = new IntersectionObserver(e => e.forEach(x => {
  if (x.isIntersecting) {
    navLinks.forEach(l => l.classList.remove('active'));
    const m = document.querySelector('.tb-nav a[href="#' + x.target.id + '"]');
    if (m) m.classList.add('active');
  }
}), { rootMargin: '-35% 0px -60% 0px' });
document.querySelectorAll('section[id]').forEach(s => so.observe(s));

// FAQ accordion
function toggleFaq(el) {
  const item = el.closest('.faq-item');
  const open = item.classList.contains('open');
  document.querySelectorAll('.faq-item').forEach(i => i.classList.remove('open'));
  if (!open) item.classList.add('open');
}
</script>
