{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>AX 내재화 전략 2026</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
<style>
/* ===== DESIGN TOKENS ===== */
:root {
  --red: #A50034;
  --red-mid: #c4003d;
  --red-light: #f9e6ec;
  --dark: #0f0f0f;
  --g900: #111;
  --g800: #1a1a1a;
  --g700: #252525;
  --g600: #333;
  --g500: #4b4b4d;
  --g400: #787a7d;
  --g300: #c8c8c8;
  --g200: #e0e0e0;
  --g100: #f4f4f4;
  --g50: #f9f9f9;
  --white: #fff;
  --yellow: #FBBF24;
  --teal: #0a6b50;
  --teal2: #1d9e75;
  --teal-light: #e1f5ee;
  --teal-border: #5dcaa5;
  --amber: #8a4e08;
  --amber2: #ba7517;
  --amber-light: #faeeda;
  --amber-border: #ef9f27;
  --purple: #26215c;
  --purple2: #534ab7;
  --purple-light: #eeedfe;
  --purple-border: #afa9ec;
  --font: 'Noto Sans KR', system-ui, sans-serif;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body { font-family: var(--font); background: var(--g100); color: var(--g800); line-height: 1.7; overflow-x: hidden; }

/* ===== TOP BAR ===== */
.top-bar {
  background: rgba(0,0,0,.88);
  backdrop-filter: blur(12px);
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 48px; height: 52px;
  position: fixed; top: 0; left: 0; right: 0; z-index: 200;
  border-bottom: 1px solid rgba(255,255,255,.06);
}
.tb-left { display: flex; align-items: center; gap: 14px; }
.lg-logo { font-size: 19px; font-weight: 900; color: var(--red); letter-spacing: -0.5px; }
.tb-div { width: 1px; height: 16px; background: rgba(255,255,255,.15); }
.tb-title { font-size: 14px; color: rgba(255,255,255,.55); font-weight: 300; letter-spacing: .04em; }
.tb-nav { display: flex; gap: 4px; }
.tb-nav a {
  font-size: 11px; font-weight: 700; color: rgba(255,255,255,.35);
  text-decoration: none; padding: 5px 10px; border-radius: 4px;
  letter-spacing: .05em; transition: all .15s;
}
.tb-nav a:hover { color: var(--white); background: rgba(255,255,255,.08); }
.tb-nav a.act { color: var(--white); }
.tb-meta { font-size: 11px; color: rgba(255,255,255,.25); letter-spacing: .06em; }

/* ===== HERO ===== */
.hero {
  margin-top: 52px;
  min-height: 100vh;
  display: flex; flex-direction: column; justify-content: flex-end;
  padding: 0 80px 80px;
  background: linear-gradient(165deg, #080808 0%, #0d0d1a 35%, #101428 60%, #0a1232 100%);
  position: relative; overflow: hidden; color: var(--white);
}
.hero::before {
  content: '';
  position: absolute; top: -20%; left: -10%;
  width: 70%; height: 140%;
  background: radial-gradient(ellipse at 30% 40%, rgba(165,0,52,.12) 0%, transparent 65%);
  pointer-events: none;
}
.hero::after {
  content: '';
  position: absolute; top: 10%; right: 0;
  width: 55%; height: 90%;
  background: radial-gradient(ellipse at 70% 30%, rgba(83,74,183,.1) 0%, transparent 65%);
  pointer-events: none;
}
.hero-grid-lines {
  position: absolute; inset: 0;
  background-image: repeating-linear-gradient(0deg, transparent, transparent 59px, rgba(255,255,255,.018) 60px);
  pointer-events: none;
}
.hero-content { position: relative; z-index: 1; max-width: 720px; }
.hero-eyebrow {
  font-size: 11px; font-weight: 700;
  color: rgba(165,0,52,.8); letter-spacing: .18em; text-transform: uppercase;
  margin-bottom: 24px; display: flex; align-items: center; gap: 12px;
}
.hero-eyebrow::before { content: ''; width: 28px; height: 1px; background: var(--red); opacity: .7; }
.hero-h1 {
  font-size: clamp(44px, 6.5vw, 82px);
  font-weight: 900; line-height: 1.05; letter-spacing: -2px;
  color: #f0ede8; margin-bottom: 6px;
}
.hero-h1 .ghost {
  color: transparent;
  -webkit-text-stroke: 1px rgba(240,237,232,.35);
}
.hero-desc {
  font-size: 16px; color: rgba(240,237,232,.45);
  font-weight: 300; margin-bottom: 56px; letter-spacing: -.2px;
}
.hero-kpi-row {
  display: grid; grid-template-columns: repeat(4, auto);
  gap: 0; border-top: 1px solid rgba(255,255,255,.08);
  padding-top: 32px; max-width: 640px;
}
.hkpi {
  padding: 0 28px 0 0;
  border-right: 1px solid rgba(255,255,255,.08);
  margin-right: 28px;
}
.hkpi:last-child { border-right: none; margin-right: 0; padding-right: 0; }
.hkpi-val { font-size: 34px; font-weight: 900; color: var(--red); line-height: 1; margin-bottom: 5px; }
.hkpi-label { font-size: 11px; color: rgba(255,255,255,.28); font-weight: 500; line-height: 1.4; letter-spacing: .02em; }

/* ===== SECTION SHELL ===== */
.sec-wrap { max-width: 920px; margin: 0 auto; padding: 96px 48px; }
.sec-wrap-wide { max-width: 1100px; margin: 0 auto; padding: 80px 48px; }
.sec-stripe { border-bottom: 1px solid var(--g200); }
.sec-stripe:nth-child(odd) { background: var(--white); }
.sec-stripe:nth-child(even) { background: var(--g50); }
.sec-dark { background: var(--g800) !important; }

.sec-mark {
  display: flex; align-items: center; gap: 14px; margin-bottom: 40px;
  opacity: 0; transform: translateY(12px);
  transition: opacity .55s ease, transform .55s ease;
}
.sec-mark.vis { opacity: 1; transform: translateY(0); }
.sec-num {
  font-size: 10px; font-weight: 700; letter-spacing: .16em;
  color: var(--red); text-transform: uppercase;
}
.sec-dark .sec-num { color: rgba(165,0,52,.7); }
.sec-line { height: 1px; flex: 1; background: var(--g200); }
.sec-dark .sec-line { background: rgba(255,255,255,.08); }

.sec-title {
  font-size: clamp(26px, 3.2vw, 38px);
  font-weight: 900; line-height: 1.2; letter-spacing: -1px;
  color: var(--g900); margin-bottom: 16px;
}
.sec-dark .sec-title { color: #f0ede8; }

.sec-body {
  font-size: 15px; line-height: 1.85; color: var(--g500);
  margin-bottom: 20px; max-width: 740px;
}
.sec-body strong { color: var(--g800); font-weight: 700; }
.sec-dark .sec-body { color: rgba(240,237,232,.55); }
.sec-dark .sec-body strong { color: #e8e5ff; }

/* Reveal */
.rv {
  opacity: 0; transform: translateY(16px);
  transition: opacity .55s ease, transform .55s ease;
}
.rv.vis { opacity: 1; transform: translateY(0); }

/* ===== PULL QUOTE ===== */
.pull {
  border-left: 3px solid var(--red);
  background: rgba(165,0,52,.04);
  border-radius: 0 8px 8px 0;
  padding: 18px 24px; margin: 28px 0; max-width: 740px;
}
.pull p { font-size: 16px; line-height: 1.65; color: var(--g800); font-style: italic; font-weight: 500; }
.pull.teal { border-left-color: var(--teal2); background: rgba(29,158,117,.04); }
.pull.teal p { color: var(--teal); }
.pull.amber { border-left-color: var(--amber2); background: rgba(138,78,8,.04); }
.sec-dark .pull { background: rgba(255,255,255,.04); border-left-color: rgba(165,0,52,.6); }
.sec-dark .pull p { color: rgba(240,237,232,.7); }
.sec-dark .pull.amber { border-left-color: rgba(186,117,23,.7); background: rgba(186,117,23,.07); }

/* ===== VIZ BOX (white card container) ===== */
.viz-box {
  background: var(--white);
  border: 1px solid var(--g200);
  border-radius: 16px;
  overflow: hidden;
  margin: 32px 0;
  box-shadow: 0 4px 24px rgba(0,0,0,.05);
}
.viz-box.dark {
  background: #12131e;
  border-color: rgba(255,255,255,.07);
}

/* ===== COPILOT FLOW (3-col) ===== */
.cf-wrap {
  display: grid;
  grid-template-columns: 1fr auto 1fr auto 1fr;
  align-items: center; gap: 0; padding: 36px 32px;
}
.cf-col { display: flex; flex-direction: column; align-items: center; gap: 10px; }
.cf-box { border-radius: 12px; padding: 22px 18px; text-align: center; width: 100%; }
.cf-box.bef { background: #f3f2ed; border: 1px solid #d3d1c7; }
.cf-box.od  { background: var(--teal-light); border: 1px solid var(--teal-border); }
.cf-box.cp  { background: var(--purple-light); border: 1px solid var(--purple-border); }
.cf-tag { font-size: 10px; letter-spacing: 1.5px; margin-bottom: 8px; font-weight: 700; text-transform: uppercase; }
.cf-box.bef .cf-tag { color: #888780; }
.cf-box.od  .cf-tag { color: var(--teal); }
.cf-box.cp  .cf-tag { color: var(--purple2); }
.cf-box-title { font-size: 15px; font-weight: 700; margin-bottom: 8px; }
.cf-box.bef .cf-box-title { color: #444441; }
.cf-box.od  .cf-box-title { color: #085041; }
.cf-box.cp  .cf-box-title { color: var(--purple); }
.cf-items { list-style: none; font-size: 12px; line-height: 1.8; text-align: left; }
.cf-box.bef .cf-items { color: #888780; }
.cf-box.od  .cf-items { color: #085041; }
.cf-box.od  .cf-items li::before { content: '› '; color: var(--teal2); }
.cf-box.cp  .cf-items { color: var(--purple); }
.cf-box.cp  .cf-items li::before { content: '› '; color: var(--purple2); }
.cf-arrow { display: flex; flex-direction: column; align-items: center; gap: 5px; padding: 0 10px; }
.cf-arrow-icon { font-size: 20px; color: var(--g300); }
.cf-arrow-label { font-size: 9px; letter-spacing: 1px; color: var(--g400); text-transform: uppercase; white-space: nowrap; }

/* ===== TOOL PAIR (2-col) ===== */
.tool-pair {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 1px; background: var(--g200);
  border: 1px solid var(--g200); border-radius: 14px;
  overflow: hidden; margin: 28px 0;
}
.tool-card { background: var(--white); padding: 30px 26px; transition: background .2s; }
.tool-card:hover { background: var(--g50); }
.tool-badge {
  font-size: 10px; letter-spacing: 2px; margin-bottom: 14px;
  font-weight: 700; text-transform: uppercase;
}
.tool-card.ag .tool-badge { color: var(--teal); }
.tool-card.lv .tool-badge { color: var(--purple2); }
.tool-name { font-size: 19px; font-weight: 900; margin-bottom: 8px; color: var(--g900); }
.tool-role {
  font-size: 12px; font-weight: 700; padding: 4px 12px;
  border-radius: 20px; display: inline-block; margin-bottom: 14px;
}
.tool-card.ag .tool-role { background: rgba(10,107,80,.09); color: var(--teal); }
.tool-card.lv .tool-role { background: rgba(83,74,183,.09); color: var(--purple2); }
.tool-desc { font-size: 13.5px; line-height: 1.75; color: var(--g400); margin-bottom: 14px; }
.tool-example {
  padding: 12px 14px; background: var(--g100);
  border-radius: 8px; font-size: 12.5px; line-height: 1.65; color: var(--g500);
  border-left: 3px solid var(--g300);
}
.tool-example strong { color: var(--g800); }

/* ===== LEVEL STEPPER ===== */
.lv-nav {
  display: flex; gap: 8px; padding: 24px 24px 0; flex-wrap: wrap;
}
.lv-btn {
  cursor: pointer; border: 1px solid var(--g200); border-radius: 8px;
  padding: 8px 18px; font-size: 12px; font-family: var(--font);
  background: var(--g100); color: var(--g400); transition: .18s; font-weight: 600;
}
.lv-btn:hover { background: var(--white); color: var(--g800); }
.lv-btn.active { color: var(--white); border-color: transparent; }
.lv-btn.lv1.active { background: #c0421a; }
.lv-btn.lv2.active { background: #9e5c08; }
.lv-btn.lv3.active { background: var(--purple2); }
.lv-btn.lv4.active { background: var(--g800); }
.lv-prog-wrap { padding: 14px 24px 0; }
.lv-prog { height: 3px; background: var(--g200); border-radius: 2px; overflow: hidden; }
.lv-prog-fill { height: 100%; border-radius: 2px; background: #c0421a; width: 25%; transition: width .4s, background .3s; }
.lv-panel {
  padding: 24px 24px 28px;
  display: grid; grid-template-columns: 1fr auto;
  gap: 24px; min-height: 180px;
}
.lv-badge-txt { font-size: 10px; font-weight: 700; letter-spacing: 1.5px; margin-bottom: 8px; text-transform: uppercase; }
.lv-name-txt { font-size: 22px; font-weight: 900; color: var(--g900); margin-bottom: 6px; }
.lv-def-txt { font-size: 13px; color: var(--g400); line-height: 1.55; margin-bottom: 16px; }
.lv-content-txt {
  font-size: 13.5px; line-height: 1.75; color: var(--g600);
  border-left: 2px solid var(--g200); padding-left: 14px;
}
.lv-right { text-align: right; min-width: 160px; }
.lv-time-txt { font-size: 24px; font-weight: 900; color: var(--g900); font-variant-numeric: tabular-nums; }
.lv-time-sub { font-size: 11px; color: var(--g400); margin-bottom: 14px; }
.lv-zone-pill { font-size: 11px; padding: 4px 12px; border-radius: 20px; display: inline-block; font-weight: 700; }
.lv-targets { margin-top: 14px; display: flex; gap: 6px; flex-wrap: wrap; justify-content: flex-end; }
.lv-target-pill { font-size: 11px; padding: 3px 10px; border-radius: 20px; background: var(--g100); color: var(--g400); font-weight: 500; }
.lv-hint { padding: 12px 24px 20px; font-size: 12px; color: var(--g400); border-top: 1px solid var(--g200); text-align: center; }
.lv-hint strong { color: var(--g700); }

/* ===== AGENT 2-GRID ===== */
.agent-grid {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 1px; background: rgba(255,255,255,.06);
  border: 1px solid rgba(255,255,255,.06);
  border-radius: 14px; overflow: hidden; margin: 32px 0;
}
.agent-card { padding: 28px 24px; background: rgba(255,255,255,.03); }
.agent-badge { font-size: 10px; letter-spacing: 2px; font-weight: 700; text-transform: uppercase; margin-bottom: 12px; }
.agent-card.amber .agent-badge { color: var(--amber-border); }
.agent-card.purple .agent-badge { color: var(--purple-border); }
.agent-title { font-size: 18px; font-weight: 700; margin-bottom: 10px; }
.agent-card.amber .agent-title { color: #fae3b0; }
.agent-card.purple .agent-title { color: #e8e5ff; }
.agent-desc { font-size: 13px; line-height: 1.75; color: rgba(240,237,232,.55); margin-bottom: 16px; }
.agent-goal {
  padding: 12px 14px; border-radius: 8px; font-size: 12px;
}
.agent-card.amber .agent-goal { background: rgba(186,117,23,.1); border: 1px solid rgba(186,117,23,.25); }
.agent-card.amber .agent-goal-label { font-size: 11px; color: var(--amber-border); font-weight: 700; margin-bottom: 4px; }
.agent-card.amber .agent-goal-txt { color: #fae3b0; font-size: 12.5px; }
.agent-card.purple .agent-goal { background: rgba(90,82,213,.12); border: 1px solid rgba(90,82,213,.25); }
.agent-card.purple .agent-goal-label { font-size: 11px; color: var(--purple-border); font-weight: 700; margin-bottom: 4px; }
.agent-card.purple .agent-goal-txt { color: #e8e5ff; font-size: 12.5px; }

/* ===== CYCLE DIAGRAM ===== */
.cycle-wrap { padding: 36px 28px 28px; }
.cycle-nodes { display: flex; align-items: center; gap: 0; justify-content: space-between; }
.cy-node { flex: 1; display: flex; flex-direction: column; align-items: center; gap: 8px; cursor: default; }
.cy-box { border-radius: 10px; padding: 14px 10px; text-align: center; width: 100%; transition: transform .15s, box-shadow .15s; }
.cy-box:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(0,0,0,.08); }
.cy-box.teal   { background: var(--teal-light); border: 1px solid var(--teal-border); }
.cy-box.purple { background: var(--purple-light); border: 1px solid var(--purple-border); }
.cy-box.red    { background: var(--red-light); border: 1px solid rgba(165,0,52,.3); }
.cy-label { font-size: 13px; font-weight: 700; line-height: 1.3; }
.cy-box.teal   .cy-label { color: #085041; }
.cy-box.purple .cy-label { color: var(--purple); }
.cy-box.red    .cy-label { color: var(--red); }
.cy-sub { font-size: 10px; margin-top: 3px; }
.cy-box.teal   .cy-sub { color: var(--teal); }
.cy-box.purple .cy-sub { color: var(--purple2); }
.cy-box.red    .cy-sub { color: var(--red-mid); }
.cy-goal { font-size: 10px; color: var(--g400); text-align: center; padding-top: 5px; line-height: 1.4; font-weight: 600; }
.cy-arrow { font-size: 14px; color: var(--g300); padding: 0 6px; flex-shrink: 0; margin-bottom: 28px; }
.cy-feedback {
  font-size: 12px; color: var(--g400); text-align: center;
  margin-top: 12px; padding: 8px;
  border: 1px dashed rgba(165,0,52,.25); border-radius: 8px;
}
.cy-outcome {
  margin-top: 20px;
  background: var(--red-light); border: 1px solid rgba(165,0,52,.2);
  border-radius: 12px; padding: 18px 24px; text-align: center;
}
.cy-outcome-title { font-size: 15px; font-weight: 900; color: var(--red); margin-bottom: 4px; }
.cy-outcome-sub { font-size: 13px; color: var(--red-mid); }

/* ===== CLOSING ===== */
.closing-wrap {
  background: linear-gradient(165deg, #0a0a0a 0%, #0f0f18 50%, #0a1228 100%);
  padding: 100px 0 80px;
}
.closing-inner { max-width: 680px; margin: 0 auto; text-align: center; padding: 0 40px; }
.close-tag {
  font-size: 10px; letter-spacing: 3px; text-transform: uppercase;
  color: rgba(255,255,255,.2); margin-bottom: 28px;
}
.close-title {
  font-size: clamp(30px, 4.5vw, 52px); font-weight: 900;
  color: #f0ede8; line-height: 1.2; margin-bottom: 28px; letter-spacing: -1px;
}
.close-title .accent { color: var(--red); }
.close-body {
  font-size: 14.5px; line-height: 1.9;
  color: rgba(240,237,232,.45); margin-bottom: 20px;
}
.close-quote {
  font-size: 19px; font-weight: 700; font-style: italic;
  color: rgba(165,0,52,.75); margin-top: 40px; letter-spacing: -.3px;
}

/* ===== FOOTER ===== */
footer {
  background: var(--g900); padding: 26px 48px;
  display: flex; align-items: center; justify-content: space-between;
  border-top: 1px solid rgba(255,255,255,.04);
}
.lf-left { font-size: 13px; color: rgba(255,255,255,.22); }
.lf-left strong { color: rgba(255,255,255,.5); }
.lf-right { font-size: 11px; color: rgba(255,255,255,.15); letter-spacing: .08em; }

/* ===== RESPONSIVE ===== */
@media(max-width: 1100px) {
  .hero { padding: 0 48px 60px; }
  .sec-wrap, .sec-wrap-wide { padding: 72px 32px; }
  .hero-kpi-row { grid-template-columns: repeat(2, auto); gap: 24px; }
  .hkpi { border-right: none; margin-right: 0; padding-right: 0; }
}
@media(max-width: 768px) {
  .top-bar { padding: 0 20px; }
  .tb-nav { display: none; }
  .hero { padding: 0 28px 52px; min-height: auto; padding-top: 80px; }
  .sec-wrap, .sec-wrap-wide { padding: 56px 20px; }
  .cf-wrap { grid-template-columns: 1fr; }
  .cf-arrow { display: none; }
  .tool-pair { grid-template-columns: 1fr; }
  .agent-grid { grid-template-columns: 1fr; }
  .cycle-nodes { flex-direction: column; gap: 4px; }
  .cy-arrow { display: none; }
  .cy-node { width: 100%; }
  .cy-box { max-width: 100%; }
  .lv-panel { grid-template-columns: 1fr; }
  footer { flex-direction: column; gap: 6px; text-align: center; }
}
</style>
</head>
