<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@300;400;600;700&family=Noto+Sans+KR:wght@300;400;500;700&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
:root {
  --ink: #0c0e1a;
  --ink2: #1a1d30;
  --surface: #f4f2ed;
  --sur2: #eceae3;
  --line: rgba(12,14,26,.1);
  --red: #c8102e;
  --red2: #e8193a;
  --red-dim: rgba(200,16,46,.07);
  --green: #0a6b50;
  --green2: #1d9e75;
  --green-dim: rgba(10,107,80,.07);
  --blue: #1a4080;
  --blue2: #2563b0;
  --blue-dim: rgba(26,64,128,.07);
  --amber: #8a4e08;
  --amber2: #ba7517;
  --amber-dim: rgba(138,78,8,.07);
  --muted: #6b6880;
  --serif: 'Noto Serif KR', serif;
  --sans: 'Noto Sans KR', sans-serif;
  --mono: 'DM Mono', monospace;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body { background: var(--surface); color: var(--ink); font-family: var(--sans); font-size: 16px; line-height: 1.8; overflow-x: hidden; }

/* ── NAV ── */
nav {
  position: fixed; top: 0; left: 0; right: 0; z-index: 100;
  background: rgba(244,242,237,.93); backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--line);
  padding: 0 48px; height: 52px;
  display: flex; align-items: center; justify-content: space-between;
}
.nav-brand { font-family: var(--mono); font-size: 11px; letter-spacing: 2px; color: var(--muted); display: flex; align-items: center; gap: 8px; }
.nav-dot { width: 6px; height: 6px; background: var(--red); border-radius: 50%; }
.nav-links { display: flex; gap: 24px; list-style: none; }
.nav-links a { font-size: 12px; font-weight: 500; color: var(--muted); text-decoration: none; transition: color .2s; }
.nav-links a:hover, .nav-links a.active { color: var(--red); }
.nav-meta { font-family: var(--mono); font-size: 10px; color: rgba(12,14,26,.25); letter-spacing: 1px; }

/* ── HERO ── */
.hero {
  min-height: 100vh;
  display: flex; flex-direction: column; justify-content: center;
  padding: 0 80px;
  background: var(--ink2);
  overflow: hidden; position: relative;
}
.hero-bg {
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse 55% 55% at 65% 45%, rgba(200,16,46,.22) 0%, transparent 70%),
    radial-gradient(ellipse 35% 50% at 15% 75%, rgba(26,64,128,.15) 0%, transparent 60%);
}
.hero-content { position: relative; z-index: 1; max-width: 700px; }
.hero-eyebrow {
  font-family: var(--mono); font-size: 11px; letter-spacing: 3px;
  color: rgba(200,16,46,.8); margin-bottom: 24px;
  display: flex; align-items: center; gap: 12px;
}
.hero-eyebrow::before { content: ''; display: block; width: 28px; height: 1px; background: rgba(200,16,46,.6); }
.hero h1 {
  font-family: var(--serif); font-size: clamp(44px,6.5vw,80px);
  font-weight: 700; line-height: 1.1; letter-spacing: -1px;
  color: #f0ede8; margin-bottom: 0;
}
.hero h1 em { font-style: normal; color: transparent; -webkit-text-stroke: 1px rgba(240,237,232,.4); }
.hero-kpis {
  display: flex; gap: 48px; flex-wrap: wrap;
  margin-top: 56px; padding-top: 32px;
  border-top: 1px solid rgba(255,255,255,.08);
}
.kpi { display: flex; flex-direction: column; gap: 4px; }
.kpi-n { font-family: var(--serif); font-size: 40px; font-weight: 700; line-height: 1; color: var(--red); }
.kpi-l { font-size: 11px; font-weight: 500; letter-spacing: .06em; color: rgba(240,237,232,.3); text-transform: uppercase; }

/* ── SECTION SHELL ── */
.section { max-width: 880px; margin: 0 auto; padding: 100px 40px; }
.section-wide { max-width: 1060px; margin: 0 auto; padding: 80px 40px; }
.dark-bg { background: var(--ink2); color: #f0ede8; }
.tint-bg { background: var(--sur2); }

.sec-mark { display: flex; align-items: center; gap: 14px; margin-bottom: 44px; }
.sec-num { font-family: var(--mono); font-size: 11px; letter-spacing: 2px; color: var(--muted); }
.sec-line { height: 1px; flex: 1; background: var(--line); }
.dark-bg .sec-num { color: rgba(255,255,255,.22); }
.dark-bg .sec-line { background: rgba(255,255,255,.08); }

h2.sec-title {
  font-family: var(--serif); font-size: clamp(26px,3.5vw,38px);
  font-weight: 700; line-height: 1.25; letter-spacing: -.4px;
  color: var(--ink); margin-bottom: 20px;
}
.dark-bg h2.sec-title { color: #f0ede8; }

p.body { font-size: 15px; line-height: 1.9; color: #2a2d40; margin-bottom: 18px; }
p.body strong { font-weight: 700; color: var(--ink); }
.dark-bg p.body { color: rgba(240,237,232,.62); }
.dark-bg p.body strong { color: #f0ede8; }

/* ── PULL QUOTE ── */
.pull {
  margin: 36px 0; padding: 22px 30px;
  border-left: 3px solid var(--red);
  background: var(--red-dim);
  border-radius: 0 8px 8px 0;
}
.pull p { font-family: var(--serif); font-size: 17px; line-height: 1.6; color: var(--ink); font-style: italic; }
.pull.green { border-left-color: var(--green2); background: var(--green-dim); }
.pull.blue  { border-left-color: var(--blue2);  background: var(--blue-dim); }
.pull.amber { border-left-color: var(--amber2); background: var(--amber-dim); }
.dark-bg .pull { background: rgba(255,255,255,.04); border-left-color: rgba(200,16,46,.6); }
.dark-bg .pull p { color: rgba(240,237,232,.75); }

/* ── VIZ BOX ── */
.viz-box {
  background: white; border: 1px solid var(--line);
  border-radius: 16px; overflow: hidden; margin: 36px 0;
}
.viz-box.dark { background: #12141f; border-color: rgba(255,255,255,.07); }

/* ── DATA BOX ── */
.dbox {
  background: rgba(200,16,46,.04); border: 1px solid rgba(200,16,46,.14);
  border-left: 4px solid var(--red);
  border-radius: 0 8px 8px 0; padding: 22px 26px; margin: 28px 0; max-width: 760px;
}
.dbox-label { font-family: var(--mono); font-size: 10px; font-weight: 500; letter-spacing: .14em; text-transform: uppercase; color: var(--red); margin-bottom: 12px; }
.dbox ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.dbox li { font-size: 13.5px; color: #2a2d40; line-height: 1.6; padding-left: 16px; position: relative; }
.dbox li::before { content: ''; position: absolute; left: 0; top: 8px; width: 5px; height: 5px; background: var(--red); border-radius: 50%; }

/* ── SCENARIO CARDS (3-col, like tool-pair) ── */
.sc-grid { display: grid; grid-template-columns: repeat(3,1fr); gap: 1px; background: var(--line); border: 1px solid var(--line); border-radius: 14px; overflow: hidden; margin: 28px 0; }
.sc-card { background: white; padding: 0; display: flex; flex-direction: column; }
.sc-head { padding: 16px 20px; display: flex; align-items: center; gap: 12px; border-bottom: 1px solid var(--line); background: var(--surface); }
.sc-ic { width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 700; color: white; flex-shrink: 0; }
.sc-ic.blue  { background: var(--blue2); }
.sc-ic.red   { background: var(--red); }
.sc-ic.green { background: var(--green2); }
.sc-who { font-size: 13px; font-weight: 700; color: var(--ink); }
.sc-role { font-family: var(--mono); font-size: 10px; color: var(--muted); letter-spacing: .04em; margin-top: 2px; }
.sc-body { padding: 18px 20px; display: flex; flex-direction: column; gap: 10px; flex: 1; }
.sc-prob { font-size: 12.5px; color: var(--muted); font-style: italic; padding: 10px 13px; background: var(--surface); border-left: 3px solid var(--line); border-radius: 0 4px 4px 0; line-height: 1.6; }
.sc-arr { color: var(--red); font-size: 16px; font-weight: 900; text-align: center; }
.sc-int { font-size: 13.5px; font-weight: 700; color: var(--ink); line-height: 1.4; font-style: italic; }
.sc-res { font-family: var(--mono); font-size: 11px; color: var(--green); padding: 8px 12px; background: var(--green-dim); border: 1px solid rgba(10,107,80,.18); border-radius: 4px; line-height: 1.6; }

/* ── BEFORE / AFTER ── */
.ba { display: grid; grid-template-columns: 1fr 32px 1fr; gap: 0; max-width: 760px; margin: 16px 0 8px; align-items: stretch; }
.ba-c { border-radius: 6px; overflow: hidden; }
.ba-c.bef { border: 1px solid var(--line); }
.ba-c.aft { border: 1px solid rgba(10,107,80,.28); }
.ba-h { padding: 8px 14px; font-family: var(--mono); font-size: 10px; font-weight: 500; letter-spacing: .12em; }
.ba-c.bef .ba-h { background: var(--sur2); color: var(--muted); }
.ba-c.aft .ba-h { background: var(--green-dim); color: var(--green); }
.ba-b { padding: 14px 16px; font-size: 13px; color: #2a2d40; line-height: 1.6; background: white; }
.ba-arr { display: flex; align-items: center; justify-content: center; color: var(--red); font-size: 20px; font-weight: 900; }
.ba-res { max-width: 760px; margin-bottom: 28px; padding: 10px 14px; background: var(--green-dim); border: 1px solid rgba(10,107,80,.18); border-radius: 4px; font-size: 12px; font-family: var(--mono); color: var(--green); }

/* ── LAYER FLOW (pipeline) ── */
.lflow { max-width: 760px; display: flex; flex-direction: column; gap: 0; }
.lblock { border: 1px solid var(--line); border-radius: 8px; overflow: hidden; margin-bottom: 4px; }
.lhead { padding: 11px 18px; font-size: 11px; font-weight: 700; letter-spacing: .06em; text-transform: uppercase; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid var(--line); }
.lhead.l1 { background: var(--blue-dim); color: var(--blue2); }
.lhead.l2 { background: var(--amber-dim); color: var(--amber); }
.lhead.l3 { background: var(--green-dim); color: var(--green); }
.lbody { padding: 14px 18px; background: white; }
.ltags { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 10px; }
.ltag { font-family: var(--mono); font-size: 11px; padding: 4px 10px; border-radius: 3px; background: var(--sur2); border: 1px solid var(--line); color: #2a2d40; }
.lconn { text-align: center; padding: 5px 0; color: var(--red); font-size: 18px; font-weight: 900; }
.lbody p { font-size: 13px; color: #2a2d40; line-height: 1.7; }

/* ── THEORY TABLE (like lv-panel) ── */
.tstack { max-width: 760px; border: 1px solid var(--line); border-radius: 8px; overflow: hidden; margin: 28px 0; }
.trow { display: grid; grid-template-columns: 160px 1fr; border-bottom: 1px solid var(--line); }
.trow:last-child { border-bottom: none; }
.tlabel { padding: 16px 18px; border-right: 1px solid var(--line); display: flex; flex-direction: column; gap: 3px; justify-content: center; }
.tl-n { font-family: var(--serif); font-size: 26px; color: var(--line); line-height: 1; }
.tl-nm { font-size: 12px; font-weight: 700; color: #2a2d40; }
.trow:nth-child(1) .tlabel { background: var(--blue-dim); }
.trow:nth-child(2) .tlabel { background: var(--amber-dim); }
.trow:nth-child(3) .tlabel { background: var(--green-dim); }
.trow:nth-child(4) .tlabel { background: var(--red-dim); }
.tbody { padding: 16px 18px; font-size: 13px; color: #2a2d40; line-height: 1.65; background: white; }
.tbody strong { color: var(--ink); }

/* ── GANTT ── */
.gantt { max-width: 760px; border: 1px solid var(--line); border-radius: 8px; overflow: hidden; margin: 24px 0; }
.g-head { display: grid; grid-template-columns: 96px repeat(9,1fr); background: var(--sur2); border-bottom: 1px solid var(--line); }
.gh { padding: 8px 5px; font-family: var(--mono); font-size: 10px; font-weight: 500; color: var(--muted); text-align: center; border-right: 1px solid var(--line); }
.gh:last-child { border-right: none; }
.g-row { display: grid; grid-template-columns: 96px repeat(9,1fr); border-bottom: 1px solid var(--line); min-height: 42px; }
.g-row:last-child { border-bottom: none; }
.gl { display: flex; align-items: center; padding: 0 9px; font-size: 10px; font-weight: 700; border-right: 1px solid var(--line); }
.gl.fe { background: var(--blue-dim); color: var(--blue2); }
.gl.be { background: var(--amber-dim); color: var(--amber); }
.gl.an { background: var(--green-dim); color: var(--green); }
.gc { border-right: 1px solid var(--line); position: relative; padding: 6px 2px; }
.gc:last-child { border-right: none; }
.gbar { position: absolute; top: 8px; bottom: 8px; left: 3px; right: 3px; border-radius: 3px; display: flex; align-items: center; padding: 0 5px; font-size: 9px; font-weight: 600; color: rgba(255,255,255,.9); overflow: hidden; transform: scaleX(0); transform-origin: left; transition: transform .7s cubic-bezier(.16,1,.3,1); }
.gbar.loaded { transform: scaleX(1); }
.gbar.fe { background: var(--blue2); }
.gbar.be { background: var(--amber2); }
.gbar.an { background: var(--green2); }
.g-ms { display: flex; gap: 24px; padding: 12px 16px; background: var(--sur2); border-top: 1px solid var(--line); flex-wrap: wrap; }
.ms { display: flex; align-items: center; gap: 7px; font-size: 12px; }
.ms-d { color: var(--red); font-size: 13px; }
.ms-k { font-weight: 700; color: var(--ink); }
.ms-v { color: var(--muted); font-family: var(--mono); font-size: 11px; }

/* ── TABLE ── */
.tc { width: 100%; border-collapse: collapse; margin: 20px 0; font-size: 13px; max-width: 760px; }
.tc th { background: var(--ink); color: white; padding: 10px 16px; text-align: left; font-family: var(--mono); font-size: 10px; font-weight: 500; letter-spacing: .1em; text-transform: uppercase; }
.tc td { padding: 12px 16px; border-bottom: 1px solid var(--line); vertical-align: top; color: #2a2d40; line-height: 1.55; }
.tc td:first-child { font-weight: 700; color: var(--ink); white-space: nowrap; background: var(--surface); }
.tc tr:hover td { background: var(--red-dim); }
.tc tr:hover td:first-child { background: var(--red-dim); }

/* ── Q&A ACCORDION ── */
.qa-list { max-width: 760px; display: flex; flex-direction: column; gap: 12px; margin-top: 24px; }
.qa-item { border: 1px solid var(--line); border-radius: 8px; overflow: hidden; transition: border-color .2s; }
.qa-item:hover { border-color: rgba(12,14,26,.22); }
.qa-q { padding: 16px 20px; font-size: 14px; font-weight: 700; color: var(--ink); cursor: pointer; display: flex; justify-content: space-between; align-items: center; background: white; user-select: none; }
.qa-q::after { content: '+'; font-size: 20px; color: var(--red); transition: transform .2s; flex-shrink: 0; }
.qa-item.open .qa-q::after { transform: rotate(45deg); }
.qa-a { display: none; padding: 0 20px 16px; font-size: 14px; color: #2a2d40; line-height: 1.8; background: white; }
.qa-item.open .qa-a { display: block; }

/* ── PRESS RELEASE box ── */
.press-box {
  background: white; border: 1px solid var(--line); border-radius: 12px;
  padding: 32px 36px; margin: 32px 0; max-width: 760px;
}
.press-dateline { font-family: var(--mono); font-size: 10px; letter-spacing: .12em; text-transform: uppercase; color: var(--muted); margin-bottom: 14px; }
.press-lead { font-size: 15px; line-height: 1.85; color: #2a2d40; }
.press-lead strong { color: var(--ink); font-weight: 700; }

/* ── CLOSING (dark) ── */
.closing {
  background: var(--ink2);
  padding: 100px 0 80px;
}
.close-inner { max-width: 880px; margin: 0 auto; padding: 0 40px; text-align: center; }
.close-tag { font-family: var(--mono); font-size: 10px; letter-spacing: 3px; color: rgba(255,255,255,.2); margin-bottom: 28px; text-transform: uppercase; }
.close-title { font-family: var(--serif); font-size: clamp(30px,4.5vw,52px); font-weight: 700; color: #f0ede8; line-height: 1.2; margin-bottom: 28px; letter-spacing: -.5px; }
.close-body { font-size: 14.5px; line-height: 1.9; color: rgba(240,237,232,.5); max-width: 560px; margin: 0 auto 20px; }
.close-quote { font-family: var(--serif); font-size: 19px; font-style: italic; color: rgba(200,16,46,.8); margin-top: 40px; }

/* ── FOOTER ── */
footer { background: var(--ink); padding: 28px 48px; display: flex; align-items: center; justify-content: space-between; border-top: 1px solid rgba(255,255,255,.05); }
footer span { font-family: var(--mono); font-size: 10px; color: rgba(255,255,255,.18); }

/* ── REVEAL ── */
.reveal { opacity: 0; transform: translateY(20px); transition: opacity .6s ease, transform .6s ease; }
.reveal.visible { opacity: 1; transform: translateY(0); }

/* ── RESPONSIVE ── */
@media(max-width: 768px) {
  nav { padding: 0 20px; }
  .nav-links, .nav-meta { display: none; }
  .hero { padding: 0 28px; padding-top: 80px; padding-bottom: 60px; min-height: auto; }
  .section, .section-wide { padding: 64px 20px; }
  .sc-grid { grid-template-columns: 1fr; }
  .ba { grid-template-columns: 1fr; }
  .ba-arr { transform: rotate(90deg); padding: 6px 0; }
  footer { flex-direction: column; gap: 6px; text-align: center; }
}
</style>
</head>
<body>

<!-- NAV -->
<nav>
  <div class="nav-brand"><span class="nav-dot"></span>EX Intelligence</div>
  <ul class="nav-links">
    <li><a href="#s1">보도자료</a></li>
    <li><a href="#s2">고객의 목소리</a></li>
