</nav>

<!-- HERO -->
<section class="hero">
  <div class="hero-bg"></div>
  <div class="hero-content">
    <div class="hero-eyebrow">EX Intelligence · 체계 구축 보고서 · 2026</div>
    <h1>조직운영<br><em>의사결정</em> 지원</h1>
