<script>
// Gantt animation
const go = new IntersectionObserver(e => e.forEach(x => {
  if (x.isIntersecting) x.target.querySelectorAll('.gbar').forEach((b,i) => setTimeout(()=>b.classList.add('loaded'), i*65));
}), { threshold: .2 });
document.querySelectorAll('.gantt').forEach(g => go.observe(g));

// Scroll reveal
const obs = new IntersectionObserver(entries => {
  entries.forEach((e,i) => { if(e.isIntersecting) setTimeout(()=>e.target.classList.add('visible'), i*55); });
}, { threshold: 0.08, rootMargin: '0px 0px -24px 0px' });
document.querySelectorAll('.reveal').forEach(el => obs.observe(el));

// Nav active
const nl = document.querySelectorAll('.nav-links a');
const so = new IntersectionObserver(e => e.forEach(x => {
  if(x.isIntersecting){ nl.forEach(l=>l.classList.remove('active')); const m=document.querySelector('.nav-links a[href="#'+x.target.id+'"]'); if(m)m.classList.add('active'); }
}), { rootMargin: '-35% 0px -60% 0px' });
document.querySelectorAll('section[id]').forEach(s => so.observe(s));

// FAQ
function tq(el){ const it=el.closest('.qa-item'); const o=it.classList.contains('open'); document.querySelectorAll('.qa-item').forEach(i=>i.classList.remove('open')); if(!o)it.classList.add('open'); }
</script>
